7	function cardBg(product: ProductSummary, colorBy: ColorBy): string {
8	  switch (colorBy) {
9	    case 'category': return CATEGORY_COLORS[product.category]?.bg ?? '#fff'
10	    case 'licensor': {
11	      const meta = product.licensorName ? LICENSOR_META[product.licensorName] : null
12	      if (meta) {
13	        // derive a pastel tint from the first stop of the gradient
14	        const match = meta.gradient.match(/#[0-9A-Fa-f]{6}/)
15	        if (match) {
16	          const hex = match[0].slice(1)
17	          const r = parseInt(hex.slice(0, 2), 16)
18	          const g = parseInt(hex.slice(2, 4), 16)
19	          const b = parseInt(hex.slice(4, 6), 16)
20	          return `rgba(${r},${g},${b},0.12)`
21	        }
22	      }
23	      return '#F6F8FC'
24	    }
25	    case 'stage': return STAGE_COLORS[product.stageName]?.bg ?? '#fff'
26	    case 'priority': {
27	      const map: Record<string, string> = {
28	        urgent: '#FBD9D9', high: '#FBE8D2', normal: '#DEEBFB', low: '#EEF1F6',
29	      }
30	      return map[product.priority] ?? '#fff'
31	    }
32	    default: return '#fff'
33	  }
34	}
