36	const PILL_STYLES: Record<string, { bg: string; color: string }> = {
37	  blocked:   { bg: '#F6CDBC', color: '#9E3B1C' },
38	  Feedback:  { bg: '#C7E3FB', color: '#1C6BAA' },
39	  ASAP:      { bg: '#F4BBA4', color: '#8E3315' },
40	  'PI Req':  { bg: '#FBEBD3', color: '#9A6400' },
41	  'PI Pending': { bg: '#FBEBD3', color: '#9A6400' },
42	}
